1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / trivial quote ---
6	  it("quote with empty item list returns premium 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Single item base premiums (with newcomer first-insurance and fee folded in) ---
15	  it("quote for single plain sword (newcomer, 0 years) returns premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
16	    const result = processScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [
19	        {
20	          op: "quote",
21	          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
22	        },
23	      ],
24	    });
25	    expect(result).toEqual({ results: [{ premium: 115 }] });
26	  });
27	  it("quote for single plain amulet (newcomer) returns premium 71 G (60 base + 6 first-insurance + 5 fee)", () => {
28	    const result = processScenario({
29	      customer: { yearsWithMHPCO: 0 },
30	      steps: [
31	        {
32	          op: "quote",
33	          items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }],
34	        },
35	      ],
36	    });
37	    expect(result).toEqual({ results: [{ premium: 71 }] });
38	  });
39	  it("quote for single plain staff (newcomer) returns premium 93 G (80 base + 8 first-insurance + 5 fee)", () => {
40	    const result = processScenario({
41	      customer: { yearsWithMHPCO: 0 },
42	      steps: [
43	        {
44	          op: "quote",
45	          items: [{ type: "staff", material: "wood", enchantment: 1, cursed: false }],
46	        },
47	      ],
48	    });
49	    expect(result).toEqual({ results: [{ premium: 93 }] });
50	  });
51	  it("quote for single plain potion (newcomer) returns premium 49 G (40 base + 4 first-insurance + 5 fee)", () => {
52	    const result = processScenario({
53	      customer: { yearsWithMHPCO: 0 },
54	      steps: [
55	        {
56	          op: "quote",
57	          items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }],
58	        },
59	      ],
60	    });
61	    expect(result).toEqual({ results: [{ premium: 49 }] });
62	  });
63	
64	  // --- Component base premiums (building block of 3) ---
65	  it("quote for 2 runes returns base premium 50 G before policy-wide modifiers (50 + 5 first-insurance + 5 fee = 60 G)", () => {
66	    const result = processScenario({
67	      customer: { yearsWithMHPCO: 0 },
68	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
69	    });
70	    expect(result).toEqual({ results: [{ premium: 60 }] });
71	  });
72	  it("quote for 3 runes applies block: base premium 60 G (60 + 6 first-insurance + 5 fee = 71 G)", () => {
73	    const result = processScenario({
74	      customer: { yearsWithMHPCO: 0 },
75	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
76	    });
77	    expect(result).toEqual({ results: [{ premium: 71 }] });
78	  });
79	  it("quote for 4 runes returns base premium 100 G — no block since block requires exactly 3 (100 + 10 first-insurance + 5 fee = 115 G)", () => {
80	    const result = processScenario({
81	      customer: { yearsWithMHPCO: 0 },
82	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
83	    });
84	    expect(result).toEqual({ results: [{ premium: 115 }] });
85	  });
86	  it("quote for 7 runes returns base premium 175 G (one block of 3 = 60 G + 4 runes × 25 G = 100 G; 175 + 18 first-insurance + 5 fee = 198 G)", () => {
87	    const result = processScenario({
88	      customer: { yearsWithMHPCO: 0 },
89	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }] }],
90	    });
91	    expect(result).toEqual({ results: [{ premium: 198 }] });
92	  });
93	
94	  // --- 'Alike' components clarification ---
95	  it("quote for 2 runes + 1 moonstone returns base premium 75 G — no block since types differ (75 + 8 first-insurance + 5 fee = 88 G)", () => {
96	    const result = processScenario({
97	      customer: { yearsWithMHPCO: 0 },
98	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }] }],
99	    });
100	    expect(result).toEqual({ results: [{ premium: 88 }] });
101	  });
102	  it("quote for 3 runes + 3 moonstones returns base premium 120 G — two separate blocks (120 + 12 first-insurance + 5 fee = 137 G)", () => {
103	    const result = processScenario({
104	      customer: { yearsWithMHPCO: 0 },
105	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "moonstone" }, { type: "moonstone" }, { type: "moonstone" }] }],
106	    });
107	    expect(result).toEqual({ results: [{ premium: 137 }] });
108	  });
109	
110	  // --- Item-specific modifier: cursed (applies to that item only) ---
111	  it("quote for cursed sword + plain amulet (newcomer) returns policy base 160 G + 50 G curse on the sword's 100 G base, then first-insurance and fee", () => {
112	    const result = processScenario({
113	      customer: { yearsWithMHPCO: 0 },
114	      steps: [
115	        {
116	          op: "quote",
117	          items: [
118	            { type: "sword", cursed: true, material: "steel", enchantment: 3 },
119	            { type: "amulet", cursed: false, material: "silver", enchantment: 2 },
120	          ],
121	        },
122	      ],
123	    });
124	    expect(result).toEqual({ results: [{ premium: 231 }] });
125	  });
126	
127	  // --- Modifier thresholds ---
128	  it("quote for sword with enchantment exactly 5 applies high-enchantment surcharge (30 % of base premium)", () => {
129	    const result = processScenario({
130	      customer: { yearsWithMHPCO: 0 },
131	      steps: [
132	        {
133	          op: "quote",
134	          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: false }],
135	        },
136	      ],
137	    });
138	    expect(result).toEqual({ results: [{ premium: 145 }] });
139	  });
140	  it("quote for sword with enchantment 4 does NOT apply high-enchantment surcharge", () => {
141	    const result = processScenario({
142	      customer: { yearsWithMHPCO: 0 },
143	      steps: [
144	        {
145	          op: "quote",
146	          items: [{ type: "sword", material: "steel", enchantment: 4, cursed: false }],
147	        },
148	      ],
149	    });
150	    expect(result).toEqual({ results: [{ premium: 115 }] });
151	  });
152	  it("quote for cursed sword with enchantment exactly 5 applies both cursed and high-enchantment surcharges", () => {
153	    const result = processScenario({
154	      customer: { yearsWithMHPCO: 0 },
155	      steps: [
156	        {
157	          op: "quote",
158	          items: [{ type: "sword", material: "steel", enchantment: 5, cursed: true }],
159	        },
160	      ],
161	    });
162	    expect(result).toEqual({ results: [{ premium: 195 }] });
163	  });
164	  it("quote with customer who has exactly 2 years with MHPCO applies the 20 % loyalty discount", () => {
165	    const result = processScenario({
166	      customer: { yearsWithMHPCO: 2 },
167	      steps: [
168	        {
169	          op: "quote",
170	          items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
171	        },
172	      ],
173	    });
174	    expect(result).toEqual({ results: [{ premium: 95 }] });
175	  });
176	
177	  // --- Integration: newcomer with a cursed sword (spec example) ---
178	  it("integration: newcomer (0 years, first contract) cursed sword (steel, enchantment 3) returns premium 165 G", () => {
179	    const result = processScenario({
180	      customer: { yearsWithMHPCO: 0 },
181	      steps: [
182	        {
183	          op: "quote",
184	          items: [{ type: "sword", cursed: true, material: "steel", enchantment: 3 }],
185	        },
186	      ],
187	    });
188	    expect(result).toEqual({ results: [{ premium: 165 }] });
189	  });
190	
191	  // --- Integration: long-standing customer's second contract (spec example) ---
192	  it("integration: 3-years customer, 2nd quote in scenario, cursed sword (steel, enchantment 7) returns premium 160 G (loyalty + follow-up + curse + high enchantment + first-insurance per item + fee)", () => {
193	    const result = processScenario({
194	      customer: { yearsWithMHPCO: 3 },
195	      steps: [
196	        {
197	          op: "quote",
198	          items: [{ type: "sword", cursed: false, material: "steel", enchantment: 2 }],
199	        },
200	        {
201	          op: "quote",
202	          items: [{ type: "sword", cursed: true, material: "steel", enchantment: 7 }],
203	        },
204	      ],
205	    });
206	    expect(result).toEqual({ results: [{ premium: 95 }, { premium: 160 }] });
207	  });
208	
209	  // --- Rounding in MHPCO's favor ---
210	  it.todo("premium calculation that yields 197.5 G is rounded UP to 198 G");
211	  it.todo("payout calculation that yields 350.5 G is rounded DOWN to 350 G");
212	
213	  // --- Claim: standard reimbursement (no special clauses) ---
214	  it.todo("claim on plain steel sword (enchantment 3) with 500 G damage: payout 400 G (full minus 100 G deductible)");
215	  it.todo("claim on a rune (insurance value 250 G) with 200 G damage: payout 100 G (full minus 100 G deductible; runes have no enchantment/material clauses)");
216	
217	  // --- Claim: high-enchantment clause ---
218	  it.todo("claim on steel sword, enchantment 9, damage 1000 G: payout 400 G (50 % first, then deductible)");
219	
220	  // --- Claim: dragon-material clause ---
221	  it.todo("claim on dragon-material sword, enchantment 5, damage 800 G: payout 700 G (full reimbursement, then deductible)");
222	
223	  // --- Claim: both clauses — 50 % rule wins ---
224	  it.todo("claim on dragon-material sword, enchantment 9, damage 1000 G: payout 400 G (50 % rule wins, then deductible: 500 − 100)");
225	  it.todo("claim on dragon-material sword, enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies, then deductible)");
226	
227	  // --- Claim: deductible per damage event (multi-item single incident) ---
228	  it.todo("claim on sword and amulet (single dragon attack), damages [500, 300]: payout 600 G (deductible applies once per damaged item)");
229	
230	  // --- Claim: cap = 2 × insurance sum ---
231	  it.todo("policy with sword and amulet has insurance sum 1600 G; cap is 3200 G");
232	  it.todo("policy with cursed sword (modifiers make premium 165 G) has cap 2000 G — modifiers do not raise the cap");
233	  it.todo("policy with sword and 3 runes (block) has insurance sum 1750 G — block discount affects premium only, not the insurance sum");
234	
235	  // --- Claim: cap exhaustion across successive claims ---
236	  it.todo("sword policy (cap 2000 G), first claim 1500 G: payout 1400 G, remainingCap 600 G");
237	  it.todo("sword policy (cap 2000 G), second successive claim 1500 G: payout 600 G, remainingCap 0 G (reduced to remaining cap)");
238	
239	  // --- Claim: multiple items of the same type ---
240	  it.todo("policy with two swords has insurance sum 2000 G and cap 4000 G");
241	  it.todo("claim on two swords (two separate damage entries) treats each entry as separate damage with its own deductible");
242	  it.todo("claim contains more entries of a given type than the policy covers: the whole claim is rejected (error)");
243	
244	  // --- Edge cases / errors ---
245	  it.todo("quote includes an item with unknown type (e.g. broomstick): error, no results");
246	  it.todo("claim references an item not part of the policy (e.g. amulet damage when only a sword is insured): error");
247	  it.todo("claim with a negative damage amount (amount: -200): error");
248	});
